const input = $input.item.json;
const ts = new Date().toISOString();
const missingList = (input.missingFields ?? []).join(', ');

const alertText = [
  `⚠️ *YAOC2 — Capability Not Configured*`,
  ``,
  `*Capability:* ${input.capability ?? 'unknown'}`,
  `*Missing:* \`${missingList}\``,
  `*Requested by:* ${input.requester ?? 'system'}`,
  `*Context:* ${input.context ?? 'n/a'}`,
  ``,
  `*What to do:*`,
  input.instructions ?? 'Check /opt/n8n.env and restart n8n.',
  ``,
  `_Once configured, the next request will proceed automatically. No restart needed if using Infisical/dynamic env._`
].join('\n');

return [{ json: {
  alertText,
  capability: input.capability,
  missingFields: input.missingFields,
  instructions: input.instructions,
  onboarding_workflow: input.onboarding_workflow,
  requester: input.requester,
  context: input.context,
  logged_at: ts
} }];
